Here is a state-machine RFC 4180 CSV parser:

```typescript
export interface ParseCSVOptions {
  delimiter?: string;
  quote?: string;
  newline?: string;
}

export function parseCSV(input: string, options?: ParseCSVOptions): string[][] {
  const delim = options?.delimiter ?? ',';
  const quote = options?.quote ?? '"';
  const text = input.startsWith('\uFEFF') ? input.slice(1) : input;
  if (text === '') return [];
  const rows: string[][] = [];
  let row: string[] = [];
  let field = '';
  type S = 'START' | 'UNQUOTED' | 'QUOTED' | 'AFTER_QUOTE';
  let state: S = 'START';
  let i = 0;
  const len = text.length;
  const pushRow = () => { rows.push(row); row = []; };
  while (i < len) {
    const ch = text[i]!;
    if (state === 'START') {
      if (ch === quote) { state = 'QUOTED'; i++; }
      else if (ch === delim) { row.push(''); i++; }
      else if (ch === '\r') { row.push(''); pushRow(); state = 'START'; i++; if (i < len && text[i] === '\n') i++; }
      else if (ch === '\n') { row.push(''); pushRow(); state = 'START'; i++; }
      else { field += ch; state = 'UNQUOTED'; i++; }
    } else if (state === 'UNQUOTED') {
      if (ch === delim) { row.push(field); field = ''; state = 'START'; i++; }
      else if (ch === '\r') { row.push(field); field = ''; pushRow(); state = 'START'; i++; if (i < len && text[i] === '\n') i++; }
      else if (ch === '\n') { row.push(field); field = ''; pushRow(); state = 'START'; i++; }
      else { field += ch; i++; }
    } else if (state === 'QUOTED') {
      if (ch === quote) { state = 'AFTER_QUOTE'; i++; }
      else { field += ch; i++; }
    } else {
      if (ch === quote) { field += quote; state = 'QUOTED'; i++; }
      else if (ch === delim) { row.push(field); field = ''; state = 'START'; i++; }
      else if (ch === '\r') { row.push(field); field = ''; pushRow(); state = 'START'; i++; if (i < len && text[i] === '\n') i++; }
      else if (ch === '\n') { row.push(field); field = ''; pushRow(); state = 'START'; i++; }
      else { field += ch; state = 'UNQUOTED'; i++; }
    }
  }
  if (state === 'QUOTED' || state === 'AFTER_QUOTE' || field !== '' || row.length > 0) {
    row.push(field); rows.push(row);
  }
  return rows;
}
